import 'dart:convert'; import 'dart:math'; import 'package:crypto/crypto.dart'; class CryptoUtils { static String sha256(String input) => sha256Hash(input); static String sha256Hash(String input) => crypto.sha256.convert(utf8.encode(input)).toString(); static String sha256WithSalt(String input, String salt) => crypto.sha256.convert(utf8.encode(input + salt)).toString(); static String generateToken({int length = 32}) { final rng = Random.secure(); const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'; return List.generate(length, (_) => chars[rng.nextInt(chars.length)]).join(); } static String base64Encode(String input) => base64.encode(utf8.encode(input)); }